{"contents":"<script setup lang="ts">
import { computed } from 'vue'
import type { Conversation } from '@/types'
import { ChatDotRound, Delete } from '@element-plus/icons-vue'
import { ElMessageBox } from 'element-plus'

const props = defineProps<{
  conversations: Conversation[]
  activeId: number | null
}>()

const emit = defineEmits<{
  select: [conv: Conversation]
  delete: [convId: number]
}>()

function formatDate(dateStr: string): string {
  const date = new Date(dateStr)
  const now = new Date()
  const diff = now.getTime() - date.getTime()
  const days = Math.floor(diff / (1000 * 60 * 60 * 24))

  if (days === 0) {
    return '今天'
  } else if (days === 1) {
    return '昨天'
  } else if (days < 7) {
    return `${days}天前`
  } else {
    return date.toLocaleDateString('zh-CN')
  }
}

async function handleDelete(conv: Conversation, event: Event) {
  event.stopPropagation()
  try {
    await ElMessageBox.confirm('确定删除该对话吗？', '提示', {
      confirmButtonText: '确定',
      cancelButtonText: '取消',
      type: 'warning',
    })
    emit('delete', conv.id)
  } catch {
    // Cancelled
  }
}

// Group conversations by date
const groupedConversations = computed(() => {
  const groups: { label: string; items: Conversation[] }[] = []
  const now = new Date()
  const today: Conversation[] = []
  const yesterday: Conversation[] = []
  const thisWeek: Conversation[] = []
  const older: Conversation[] = []

  for (const conv of props.conversations) {
    const date = new Date(conv.updatedAt || conv.createdAt)
    const diff = Math.floor((now.getTime() - date.getTime()) / (1000 * 60 * 60 * 24))
    if (diff === 0) today.push(conv)
    else if (diff === 1) yesterday.push(conv)
    else if (diff < 7) thisWeek.push(conv)
    else older.push(conv)
  }

  if (today.length) groups.push({ label: '今天', items: today })
  if (yesterday.length) groups.push({ label: '昨天', items: yesterday })
  if (thisWeek.length) groups.push({ label: '本周', items: thisWeek })
  if (older.length) groups.push({ label: '更早', items: older })

  return groups
})
</script>

<template>
  <div class="conversation-list">
    <div v-if="conversations.length === 0" class="empty-state">
      <el-icon :size="32" color="#c0c4cc"><ChatDotRound /></el-icon>
      <p>暂无对话记录</p>
    </div>
    <template v-else>
      <div v-for="group in groupedConversations" :key="group.label" class="conv-group">
        <div class="group-label">{{ group.label }}</div>
        <div
          v-for="conv in group.items"
          :key="conv.id"
          class="conv-item"
          :class="{ active: conv.id === activeId }"
          @click="emit('select', conv)"
        >
          <el-icon class="conv-icon"><ChatDotRound /></el-icon>
          <span class="conv-title">{{ conv.title || '新对话' }}</span>
          <el-button
            :icon="Delete"
            text
            size="small"
            class="delete-btn"
            @click="handleDelete(conv, $event)"
          />
        </div>
      </div>
    </template>
  </div>
</template>

