{"contents":"import { defineStore } from 'pinia'
import { ref } from 'vue'
import * as chatApi from '@/api/chat'
import type { Conversation, Message } from '@/types'

export const useChatStore = defineStore('chat', () => {
  const conversations = ref<Conversation[]>([])
  const currentConversation = ref<Conversation | null>(null)
  const messages = ref<Message[]>([])
  const loading = ref(false)
  const streaming = ref(false)
  const streamingContent = ref('')
  const messageCache = new Map<number, Message[]>()

  async function loadConversations() {
    try {
      const res = await chatApi.getConversations()
      conversations.value = res.data.data
    } catch {
      conversations.value = []
    }
  }

  async function selectConversation(conv: Conversation) {
    currentConversation.value = conv
    // 命中缓存直接显示，不再重复请求
    if (messageCache.has(conv.id)) {
      messages.value = messageCache.get(conv.id)!
      return
    }
    loading.value = true
    try {
      const res = await chatApi.getMessages(conv.id)
      const fetched = res.data.data
      messageCache.set(conv.id, fetched)
      if (currentConversation.value?.id === conv.id) {
        messages.value = fetched
      }
    } catch {
      messages.value = []
    } finally {
      loading.value = false
    }
  }

  function newConversation() {
    currentConversation.value = null
    messages.value = []
  }

  function sendMessage(content: string) {
    // Add user message immediately
    const userMessage: Message = {
      id: Date.now(),
      conversationId: currentConversation.value?.id ?? 0,
      role: 'user',
      content,
      sources: [],
      createdAt: new Date().toISOString(),
    }
    messages.value.push(userMessage)

    // Add placeholder assistant message
    streaming.value = true
    streamingContent.value = ''
    const assistantMessage: Message = {
      id: Date.now() + 1,
      conversationId: currentConversation.value?.id ?? 0,
      role: 'assistant',
      content: '',
      sources: [],
      createdAt: new Date().toISOString(),
    }
    messages.value.push(assistantMessage)

    let fullContent = ''

    const controller = chatApi.sendMessageSSE(
      currentConversation.value?.id ?? null,
      content,
      (chunk: string) => {
        fullContent += chunk
        streamingContent.value = fullContent
        const lastMsg = messages.value[messages.value.length - 1]
        if (lastMsg && lastMsg.role === 'assistant') {
          lastMsg.content = fullContent
        }
      },
      () => {
        streaming.value = false
        streamingContent.value = ''
        // 更新缓存
        if (currentConversation.value) {
          messageCache.set(currentConversation.value.id, [...messages.value])
        }
        loadConversations()
      },
      (err: string) => {
        const lastMsg = messages.value[messages.value.length - 1]
        if (lastMsg && lastMsg.role === 'assistant') {
          lastMsg.content = `错误: ${err}`
        }
        streaming.value = false
        streamingContent.value = ''
      },
    )

    return controller
  }

  async function deleteConversation(convId: number) {
    await chatApi.deleteConversation(convId)
    messageCache.delete(convId)
    conversations.value = conversations.value.filter((c) => c.id !== convId)
    if (currentConversation.value?.id === convId) {
      currentConversation.value = null
      messages.value = []
    }
  }

  return {
    conversations,
    currentConversation,
    messages,
    loading,
    streaming,
    streamingContent,
    loadConversations,
    selectConversation,
    newConversation,
    sendMessage,
    deleteConversation,
  }
})","totalLinesInFile":134}

{"contents":"import request from './request'
import type { ApiResponse, Conversation, Message } from '@/types'

export function getConversations() {
  return request.get<ApiResponse<Conversation[]>>('/chat/conversations')
}

export function getMessages(conversationId: number) {
  return request.get<ApiResponse<Message[]>>(`/chat/conversations/${conversationId}/messages`)
}

export function deleteConversation(conversationId: number) {
  return request.delete<ApiResponse<null>>(`/chat/conversations/${conversationId}`)
}

export function submitFeedback(messageId: number, rating: 'useful' | 'useless' | 'none') {
  // 如果是取消，发送 null
  if (rating === 'none') {
    return request.post<ApiResponse<null>>('/chat/feedback', { messageId, rating: null })
  }
  return request.post<ApiResponse<null>>('/chat/feedback', { messageId, rating })
}

/**
 * Send message via fetch + SSE streaming (POST request with Bearer token)
 */
export function sendMessageSSE(
  conversationId: number | null,
  content: string,
  onMessage: (chunk: string) => void,
  onDone: () => void,
  onError: (err: string) => void,
): AbortController {
  const controller = new AbortController()
  const token = localStorage.getItem('token') || ''

  fetch('/api/chat/send', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`,
      'Accept': 'text/event-stream',
    },
    body: JSON.stringify({ conversationId, content }),
    signal: controller.signal,
  })
    .then(async (response) => {
      if (!response.ok) {
        onError(`请求失败: ${response.status}`)
        return
      }

      const reader = response.body?.getReader()
      if (!reader) {
        onError('无法读取响应流')
        return
      }

      const decoder = new TextDecoder()
      let buffer = ''

      while (true) {
        const { done, value } = await reader.read()
        if (done) break

        buffer += decoder.decode(value, { stream: true })

        // SSE event boundary is a blank line
        const events = buffer.split('\n\n')
        buffer = events.pop() || ''

        for (const eventText of events) {
          const lines = eventText.split('\n')
          let eventName = ''
          const dataParts: string[] = []

          for (const rawLine of lines) {
            const line = rawLine.replace(/\r$/, '')
            if (line.startsWith('event:')) {
              eventName = line.slice(6).trim()
            } else if (line.startsWith('data:')) {
              let part = line.slice(5)
              if (part.startsWith(' ')) part = part.slice(1)
              dataParts.push(part)
            }
          }

          const data = dataParts.join('\n')
          if (data === '[DONE]' || eventName === 'done') {
            onDone()
            return
          }

          if (data) {
            onMessage(data)
          }
        }
      }

      // Flush trailing buffer if any valid SSE event remains
      if (buffer.trim()) {
        const lines = buffer.split('\n')
        const dataParts: string[] = []
        for (const rawLine of lines) {
          const line = rawLine.replace(/\r$/, '')
          if (line.startsWith('data:')) {
            let part = line.slice(5)
            if (part.startsWith(' ')) part = part.slice(1)
            dataParts.push(part)
          }
        }
        const data = dataParts.join('\n')
        if (data && data !== '[DONE]') {
          onMessage(data)
        }
      }

      onDone()
    })
    .catch((err) => {
      if (err.name !== 'AbortError') {
        onError(err.message || '网络错误')
      }
    })

  return controller
}","totalLinesInFile":127}

{"contents":"package com.coding.assistant.controller;

import com.coding.assistant.dto.*;
import com.coding.assistant.security.SecurityUtil;
import com.coding.assistant.service.ChatService;
import com.coding.assistant.service.FeedbackService;
import com.coding.assistant.service.ProgressService;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springframework.http.MediaType;
import org.springframework.http.codec.ServerSentEvent;
import org.springframework.web.bind.annotation.*;
import reactor.core.publisher.Flux;

import java.util.List;

@RestController
@RequestMapping("/api/chat")
@RequiredArgsConstructor
public class ChatController {

    private final ChatService chatService;
    private final FeedbackService feedbackService;
    private final ProgressService progressService;

    @PostMapping(value = "/send", produces = MediaType.TEXT_EVENT_STREAM_VALUE)
    public Flux<ServerSentEvent<String>> sendMessage(@Valid @RequestBody ChatSendRequest request) {
        Long userId = SecurityUtil.getCurrentUserId();

        // Record chat action
        progressService.recordAction(userId, "chat", null);

        return chatService.sendMessage(userId, request)
                .map(content -> ServerSentEvent.<String>builder()
                        .data(content)
                        .build())
                .concatWith(Flux.just(ServerSentEvent.<String>builder()
                        .event("done")
                        .data("[DONE]")
                        .build()));
    }

    @GetMapping("/conversations")
    public ApiResponse<List<ConversationVO>> getConversations() {
        Long userId = SecurityUtil.getCurrentUserId();
        List<ConversationVO> conversations = chatService.getConversations(userId);
        return ApiResponse.success(conversations);
    }

    @GetMapping("/conversations/{id}/messages")
    public ApiResponse<List<MessageVO>> getMessages(@PathVariable Long id) {
        Long userId = SecurityUtil.getCurrentUserId();
        List<MessageVO> messages = chatService.getMessages(userId, id);
        return ApiResponse.success(messages);
    }

    @DeleteMapping("/conversations/{id}")
    public ApiResponse<Void> deleteConversation(@PathVariable Long id) {
        Long userId = SecurityUtil.getCurrentUserId();
        chatService.deleteConversation(userId, id);
        return ApiResponse.success();
    }

    @PostMapping("/feedback")
    public ApiResponse<Void> submitFeedback(@Valid @RequestBody FeedbackRequest request) {
        Long userId = SecurityUtil.getCurrentUserId();
        feedbackService.submit(userId, request);
        progressService.recordAction(userId, "feedback", String.valueOf(request.getMessageId()));
        return ApiResponse.success();
    }
}","totalLinesInFile":71}

