import { ref, onMounted } from 'vue'
import { useGraphStore } from '@/stores/graph'
import GraphRenderer from '@/components/graph/GraphRenderer.vue'
import { Search, Close, Connection } from '@element-plus/icons-vue'

const graphStore = useGraphStore()

const searchKeyword = ref('')
const showDetail = ref(false)

onMounted(() => {
  graphStore.loadOverview()
})

function handleSearch() {
  const keyword = searchKeyword.value.trim()
  if (keyword) {
    graphStore.search(keyword)
  } else {
    graphStore.loadOverview()
  }
}

function handleNodeClick(nodeId: string) {
  graphStore.selectNode(nodeId)
  graphStore.loadNeighbors(nodeId)
  showDetail.value = true
}

function closeDetail() {
  showDetail.value = false
  graphStore.clearSelection()
}

function handleRefresh() {
  searchKeyword.value = ''
  graphStore.loadOverview()
}

// Get unique categories from current nodes
const categories = ref<string[]>([])

function updateCategories() {
  const catSet = new Set<string>()
  for (const node of graphStore.nodes) {
    if (node.category) catSet.add(node.category)
  }
  categories.value = Array.from(catSet)
}

// Watch for node changes and update categories
import { watch } from 'vue'
watch(() => graphStore.nodes, updateCategories, { deep: true })

function filterByCategory(category: string) {
  graphStore.search(category)
}
</script>

<template>
  <div class="graph-view" v-loading="graphStore.loading">
    <!-- Top Bar -->
    <div class="graph-toolbar">
      <div class="search-bar">
        <el-input
          v-model="searchKeyword"
          placeholder="搜索知识节点..."
          :prefix-icon="Search"
          clearable
          size="default"
          @keyup.enter="handleSearch"
          @clear="handleRefresh"
        />
        <el-button type="primary" @click="handleSearch">搜索</el-button>
        <el-button @click="handleRefresh">
          <el-icon><Connection /></el-icon>
          重置
        </el-button>
      </div>
      <div class="category-filters">
        <el-tag
          v-for="cat in categories"
          :key="cat"
          class="category-tag"
          effect="plain"
          @click="filterByCategory(cat)"
        >
          {{ cat }}
        </el-tag>
      </div>
    </div>

    <!-- Graph Area -->
    <div class="graph-container">
      <GraphRenderer
        :nodes="graphStore.nodes"
        :edges="graphStore.edges"
        @node-click="handleNodeClick"
      />
    </div>

    <!-- Detail Panel (slide-in) -->
    <transition name="slide-right">
      <div v-if="showDetail && graphStore.selectedNode" class="detail-panel">
        <div class="detail-header">
          <h3>{{ graphStore.selectedNode.name }}</h3>
          <el-button :icon="Close" text circle @click="closeDetail" />
        </div>
        <div class="detail-body">
          <div class="detail-item">
            <label>分类</label>
            <el-tag size="small">{{ graphStore.selectedNode.category }}</el-tag>
          </div>
          <div class="detail-item">
            <label>难度</label>
            <el-tag
              size="small"
              :type="
                graphStore.selectedNode.difficulty === 'hard'
                  ? 'danger'
                  : graphStore.selectedNode.difficulty === 'medium'
                    ? 'warning'
                    : 'success'
              "
            >
              {{
                graphStore.selectedNode.difficulty === 'hard'
                  ? '困难'
                  : graphStore.selectedNode.difficulty === 'medium'
                    ? '中等'
                    : '简单'
              }}
            </el-tag>
          </div>
          <div class="detail-item">
            <label>描述</label>
            <p>{{ graphStore.selectedNode.description || '暂无描述' }}</p>
          </div>
          <div v-if="graphStore.selectedNode.keywords?.length" class="detail-item">
            <label>关键词</label>
            <div class="keyword-list">
              <el-tag
                v-for="kw in graphStore.selectedNode.keywords"
                :key="kw"
                size="small"
                type="info"
              >
                {{ kw }}
              </el-tag>
            </div>
          </div>
          <div class="detail-actions">
            <el-button type="primary" size="small" @click="handleNodeClick(graphStore.selectedNode!.id)">
              展开关联节点
            </el-button>
          </div>
        </div>
      </div>
    </transition>
  </div>
</template>

