import { ref, onMounted, computed } from 'vue'
import { useProgressStore } from '@/stores/progress'
import HeatmapChart from '@/components/dashboard/HeatmapChart.vue'
import RadarChart from '@/components/dashboard/RadarChart.vue'
import {
  Calendar,
  ChatDotRound,
  DocumentCopy,
  DataAnalysis,
  Download,
  TrendCharts,
  Warning,
  Checked,
} from '@element-plus/icons-vue'

const progressStore = useProgressStore()
const currentYear = ref(new Date().getFullYear())

onMounted(async () => {
  await Promise.all([
    progressStore.loadDashboard(),
    progressStore.loadHeatmap(currentYear.value),
    progressStore.loadRadar(),
    progressStore.loadSmartInsights(),
  ])
})

function handleYearChange(year: number) {
  currentYear.value = year
  progressStore.loadHeatmap(year)
}

function handleExportReport() {
  progressStore.downloadReport()
}

function togglePlan(planId: string, completed: boolean) {
  progressStore.toggleWeeklyPlanItem(planId, completed)
}

const statCards = computed(() => {
  const d = progressStore.dashboard
  return [
    { title: '学习天数', value: d?.totalDays ?? 0, unit: '天', icon: Calendar, color: '#409eff', bg: '#ecf5ff' },
    { title: '对话次数', value: d?.totalChats ?? 0, unit: '次', icon: ChatDotRound, color: '#67c23a', bg: '#f0f9eb' },
    { title: '代码片段', value: d?.totalSnippets ?? 0, unit: '个', icon: DocumentCopy, color: '#e6a23c', bg: '#fdf6ec' },
    { title: '知识覆盖率', value: d?.knowledgeCoverage ?? 0, unit: '%', icon: DataAnalysis, color: '#f56c6c', bg: '#fef0f0' },
  ]
})

const yearOptions = computed(() => {
  const years: number[] = []
  const current = new Date().getFullYear()
  for (let y = current; y >= current - 3; y--) years.push(y)
  return years
})

const healthColor = computed(() => {
  const score = progressStore.smartInsights?.healthScore ?? 0
  if (score >= 80) return '#67c23a'
  if (score >= 60) return '#e6a23c'
  return '#f56c6c'
})
</script>

<template>
  <div class="dashboard-view" v-loading="progressStore.loading">
    <div class="stats-row">
      <div v-for="card in statCards" :key="card.title" class="stat-card">
        <div class="stat-icon" :style="{ backgroundColor: card.bg }">
          <el-icon :size="24" :color="card.color"><component :is="card.icon" /></el-icon>
        </div>
        <div class="stat-info">
          <div class="stat-value">{{ card.value }}<span class="stat-unit">{{ card.unit }}</span></div>
          <div class="stat-title">{{ card.title }}</div>
        </div>
      </div>
    </div>

    <div class="smart-row">
      <div class="smart-card health-card">
        <div class="smart-header">
          <h3><el-icon><TrendCharts /></el-icon> 学习健康度仪表盘（综合分）</h3>
        </div>
        <div class="health-body">
          <el-progress
            type="dashboard"
            :percentage="progressStore.smartInsights?.healthScore ?? 0"
            :color="healthColor"
            :stroke-width="14"
          />
          <p class="health-tip">综合活跃度、连续学习、学习强度计算</p>
        </div>
      </div>

      <div class="smart-card weak-card">
        <div class="smart-header">
          <h3><el-icon><Warning /></el-icon> 薄弱领域 Top3</h3>
        </div>
        <div class="weak-list">
          <div v-for="area in progressStore.smartInsights?.weakAreas || []" :key="area.key" class="weak-item">
            <div class="weak-top">
              <span class="weak-name">{{ area.name }}</span>
              <el-tag size="small" :type="area.score >= 80 ? 'success' : area.score >= 60 ? 'warning' : 'danger'">
                {{ area.score }}分
              </el-tag>
            </div>
            <p class="weak-desc">{{ area.suggestion }}</p>
          </div>
        </div>
      </div>

      <div class="smart-card plan-card">
        <div class="smart-header">
          <h3><el-icon><Checked /></el-icon> 下周行动计划（可勾选完成）</h3>
        </div>
        <div class="plan-list">
          <div v-for="plan in progressStore.smartInsights?.weeklyPlan || []" :key="plan.id" class="plan-item">
            <el-checkbox :model-value="plan.completed" @change="(val) => togglePlan(plan.id, Boolean(val))">
              <span class="plan-title">{{ plan.title }}</span>
            </el-checkbox>
            <p class="plan-desc">{{ plan.description }}</p>
          </div>
        </div>
      </div>
    </div>

    <div class="charts-row">
      <div class="chart-card heatmap-card">
        <div class="chart-header">
          <h3>学习活跃度</h3>
          <el-select v-model="currentYear" size="small" style="width: 100px" @change="handleYearChange">
            <el-option v-for="year in yearOptions" :key="year" :label="`${year}年`" :value="year" />
          </el-select>
        </div>
        <div class="chart-body"><HeatmapChart :data="progressStore.heatmap" /></div>
      </div>

      <div class="chart-card radar-card">
        <div class="chart-header"><h3>知识掌握度</h3></div>
        <div class="chart-body"><RadarChart :data="progressStore.radar" /></div>
      </div>
    </div>

    <div class="export-section">
      <el-button type="primary" :icon="Download" @click="handleExportReport">导出学习报告 (PDF)</el-button>
    </div>
  </div>
</template>

